from dataclasses import dataclass, field

@dataclass
class RiskEntry:
    risk_id: str                        # e.g. "R-FAIR-001"
    title: str
    domain: RiskDomain
    description: str
    affected_stakeholders: list[str]    # ["end_users", "third_parties", ...]
    trigger_conditions: list[str]       # what must be true for the risk to materialise

    # Inherent risk — assessed without any controls in place
    inherent_severity: RiskSeverity
    inherent_likelihood: RiskLikelihood

    # Controls applied to reduce the risk
    controls: list[str]

    # Residual risk — assessed with all controls in place
    residual_severity: RiskSeverity
    residual_likelihood: RiskLikelihood

    # Treatment and ownership
    treatment: str      # "mitigate" | "accept" | "transfer" | "avoid"
    owner: str          # team or role accountable for this risk
    review_date: str    # ISO-8601 date of next review
    regulatory_references: list[str] = field(default_factory=list)

    @property
    def inherent_score(self) -> int:
        return risk_score(self.inherent_severity, self.inherent_likelihood)

    @property
    def residual_score(self) -> int:
        return risk_score(self.residual_severity, self.residual_likelihood)

    @property
    def control_effectiveness(self) -> float:
        """Fraction of inherent risk removed by controls (0.0–1.0)."""
        if self.inherent_score == 0:
            return 1.0
        return 1.0 - self.residual_score / self.inherent_score

@dataclass
class AIRiskRegister:
    system_id: str
    system_name: str
    assessment_version: str     # semver, incremented on every re-assessment
    assessment_date: str        # ISO-8601
    assessor: str
    eu_ai_act_tier: str         # "unacceptable" | "high" | "limited" | "minimal" | "gpai"
    risks: list[RiskEntry] = field(default_factory=list)

    def add(self, risk: RiskEntry) -> None:
        self.risks.append(risk)

    def high_priority(self, threshold: int = 6) -> list[RiskEntry]:
        """Risks whose residual score is at or above the threshold."""
        return sorted(
            (r for r in self.risks if r.residual_score >= threshold),
            key=lambda r: r.residual_score,
            reverse=True,
        )

    def unaccepted(self) -> list[RiskEntry]:
        """Risks above the acceptance ceiling that have not yet been treated."""
        ACCEPTANCE_CEILING = 8
        return [
            r for r in self.risks
            if r.treatment != "accept" and r.residual_score >= ACCEPTANCE_CEILING
        ]

    def by_domain(self) -> dict[str, list[RiskEntry]]:
        result: dict[str, list[RiskEntry]] = {}
        for r in self.risks:
            result.setdefault(r.domain.value, []).append(r)
        return result

    def summary(self) -> dict[str, int]:
        return {
            "total": len(self.risks),
            "high_priority": len(self.high_priority()),
            "unaccepted": len(self.unaccepted()),
            "avg_inherent_score": int(
                sum(r.inherent_score for r in self.risks) / max(len(self.risks), 1)
            ),
            "avg_residual_score": int(
                sum(r.residual_score for r in self.risks) / max(len(self.risks), 1)
            ),
        }
